styles:
.page-header {
      background: white;
      padding: 8rem 0 4rem;
      text-align: center;
      border-bottom: 1px solid var(--border);
    }
    .page-header h1 {
      font-size: clamp(2rem, 5vw, 3rem);
      margin-bottom: 1rem;
      color: var(--text-primary);
    }
    .page-header p {
      color: var(--text-secondary);
      font-size: 1.125rem;
    }
    .page-content {
      background: white;
      padding: 4rem 0;
    }
    .page-content .container {
      max-width: 800px;
    }
    .policy-section {
      margin-bottom: 3rem;
    }
    .policy-section h2 {
      font-size: 1.5rem;
      margin-bottom: 1rem;
      color: var(--text-primary);
    }
    .policy-section p {
      color: var(--text-secondary);
      line-height: 1.8;
      margin-bottom: 1rem;
    }
    .contact-info {
      background: var(--bg-secondary);
      padding: 2rem;
      border-radius: var(--radius-lg);
      margin-top: 2rem;
    }
    .contact-info h3 {
      font-size: 1.25rem;
      margin-bottom: 1rem;
      color: var(--text-primary);
    }
    .contact-info p {
      margin-bottom: 0.5rem;
    }
    .contact-info a {
      color: var(--primary);
    }
    .contact-info a:hover {
      text-decoration: underline;
    }
    .last-updated {
      color: var(--text-muted);
      font-size: 0.875rem;
      margin-bottom: 2rem;
    }
    @media (max-width: 768px) {
      .page-header {
        padding: 6rem 0 3rem;
      }
      .page-content {
        padding: 3rem 0;
      }
    }
